class MinStack:
    def __init__(self):
        self.st = []
        self.min_st = []
    def push(self, val):
        self.st.append(val)
        m = val if not self.min_st else min(val, self.min_st[-1])
        self.min_st.append(m)
    def pop(self):
        self.st.pop()
        self.min_st.pop()
    def top(self):
        return self.st[-1]
    def getMin(self):
        return self.min_st[-1]

