class MyQueue:
    def __init__(self):
        self.inp = []
        self.out = []
    def push(self, x):
        self.inp.append(x)
    def pop(self):
        self.peek()
        return self.out.pop()
    def peek(self):
        if not self.out:
            while self.inp:
                self.out.append(self.inp.pop())
        return self.out[-1]
    def empty(self):
        return not self.inp and not self.out

