class MyQueue {
    stack<int> inp, out;
    void shift() {
        if (out.empty()) {
            while (!inp.empty()) {
                out.push(inp.top());
                inp.pop();
            }
        }
    }
public:
    void push(int x) { inp.push(x); }
    int pop() {
        shift();
        int val = out.top(); out.pop();
        return val;
    }
    int peek() {
        shift();
        return out.top();
    }
    bool empty() { return inp.empty() && out.empty(); }
};

