def evalRPN(tokens):
    st = []
    for t in tokens:
        if t in '+-*/':
            b = st.pop()
            a = st.pop()
            if t == '+': st.append(a + b)
            elif t == '-': st.append(a - b)
            elif t == '*': st.append(a * b)
            elif t == '/': st.append(int(a / b)) # Truncates towards zero
        else:
            st.append(int(t))
    return st[0]

