string simplifyPath(string path) {
    vector<string> st;
    stringstream ss(path);
    string part;
    while (getline(ss, part, '/')) {
        if (part == "..") {
            if (!st.empty()) st.pop_back();
        } else if (part != "" && part != ".") {
            st.push_back(part);
        }
    }
    string res = "";
    for (string s : st) res += "/" + s;
    return res.empty() ? "/" : res;
}

