            while st and st[-1][1] > h:
                idx, height = st.pop()
                area = max(area, height * (i - idx))
                start = idx
            st.append((start, h))
        for i, h in st:
            area = max(area, h * (len(heights) - i))
        return area

    for row in matrix:
        for c in range(cols):
